// Payload esperado (do Colab ou ESP32):
// { "sensor_id": "s1", "temperatura": 25.5, "umidade": 65.2, ... }
// ou { "temperatura": 25.5 } (sem sensor_id)

const payload = msg.payload;

if (typeof payload !== 'object' || payload === null) {
    node.warn('Payload inválido: ' + JSON.stringify(payload));
    return null;
}

// Campos que NÃO são métricas numéricas
const SKIP_FIELDS = ['sensor_id', 'device_id', 'timestamp', 'ts'];

// Tag de identificação do sensor
const sensorId = String(payload.sensor_id || payload.device_id || 's1');

// Monta fields como NÚMEROS (não strings!)
const fields = {};
for (const [key, val] of Object.entries(payload)) {
    if (SKIP_FIELDS.includes(key)) continue;
    const num = parseFloat(val);
    if (!isNaN(num)) {
        fields[key] = num;  // garantido numérico
    }
}

if (Object.keys(fields).length === 0) {
    node.warn('Nenhum campo numérico encontrado: ' + JSON.stringify(payload));
    return null;
}

// Formato esperado pelo node-red-contrib-influxdb (v2)
msg.payload = [
    {
        measurement: 'sensores',
        tags: {
            sensor_id: sensorId
        },
        fields: fields,
        timestamp: new Date()
    }
];

node.log('Enviando ao InfluxDB: sensor=' + sensorId + ' fields=' + JSON.stringify(fields));
return msg;
